form:Form.form:Scripts:
		function Validar()
{
	if (Ctrl('main').GetMode() == "SHOW")
		return true;

	if (Ctrl('oi_curso').GetXValue() == "" && Ctrl('d_curso_ext_per').GetXValue() =="")
		Ctrl('oi_curso').SetError('Debe ingresar Curso o Descripción');
	else
	{
		if (Ctrl('oi_curso').GetXValue() != "" && Ctrl('d_curso_ext_per').GetXValue() !="")
			Ctrl('oi_curso').SetError('Debe ingresar Curso o Descripción');
		else
			return true;
	} 	
}
